package kvstore

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/kvstore"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type KVStoreProxy struct {
	kvstore.UnimplementedKVStoreServer
	client kvstore.KVStoreClient
}

func init() {
	proxyutil.Register(&kvstore.KVStore_ServiceDesc, NewKVStoreProxy)
}
func NewKVStoreProxy(cc grpc.ClientConnInterface) kvstore.KVStoreServer {
	return &KVStoreProxy{client: kvstore.NewKVStoreClient(cc)}
}
func (p *KVStoreProxy) Put(ctx context.Context, in *kvstore.MessageSet) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[kvstore.MessageSet, emptypb.Empty](p.client.Put)(ctx, in)
}
func (p *KVStoreProxy) Get(ctx context.Context, in *kvstore.KeySet) (*kvstore.MessageSet, error) {
	return proxyutil.ProxyMethod[kvstore.KeySet, kvstore.MessageSet](p.client.Get)(ctx, in)
}
func (p *KVStoreProxy) Del(ctx context.Context, in *kvstore.KeySet) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[kvstore.KeySet, emptypb.Empty](p.client.Del)(ctx, in)
}
func (p *KVStoreProxy) List(ctx context.Context, in *kvstore.ListFilter) (*kvstore.KeySet, error) {
	return proxyutil.ProxyMethod[kvstore.ListFilter, kvstore.KeySet](p.client.List)(ctx, in)
}
